'1957127135': function(fixed, dollars, __ctx, ftHelper, wmjQuery) {    let panel = wmjQuery("[data-component-id='force_highlightsPanel']");
    if (panel.length > 1) {
        panel = panel.filter(":visible");
    }
    if (panel.length > 0) {
        let tgtContainer = panel.find("ul.slds-button-group-list");
        if (tgtContainer.length > 0) {
            const containerElems = tgtContainer.find(":contains(" + fixed.tgtTxt + ")");
            let res;
            if (fixed._tgtTag === "DIV") {
                res = containerElems.filter("button");
            } else if (fixed._tgtTag === "A") {
                res = containerElems.filter("lightning-button");
            } else {
                res = containerElems.filter(fixed._tgtTag);
            }
            return res.length > 1 ? res.eq(fixed._index) : res;
        }
        tgtContainer = panel.find("ul.forceActionsContainer");
        if (tgtContainer.length > 0) {
            const containerElems = tgtContainer.find(":contains(" + fixed.tgtTxt + ")");
            let res;
            if (fixed._tgtTag === "BUTTON") {
                return containerElems.filter("DIV");
            } else if (fixed._tgtTag === "LIGHTNING-BUTTON" || fixed._tgtTag === "SLOT" 
                || fixed._tgtTag === "RUNTIME_PLATFORM_ACTIONS-ACTION-RENDERER" || fixed._tgtTag === "RUNTIME_PLATFORM_ACTIONS-PAGE-REFERENCE-ACTION") {
                return containerElems.filter("A");
            } else {
                return containerElems.filter(fixed._tgtTag);
            }
        }
    } 
    return wmjQuery();},
